import React, { useEffect, useMemo, useState } from 'react';
import '../../styles/storekeeper/storekeeper-layout.css';
import '../../styles/storekeeper/storekeeper-inventory.css';
import api from '../../services/api';

const initialForm = {
  product_code: '',
  product_name: '',
  category_id: '',
  unit: '',
  supplier: '',
  description: '',
  status: 'ACTIVE',
};

const StorekeeperInventory = () => {
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(null);

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [selectedStatus, setSelectedStatus] = useState('');

  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [formData, setFormData] = useState(initialForm);

  const getStockStatus = (qty) => {
    const quantity = Number(qty || 0);
    if (quantity <= 0) return 'OUT';
    if (quantity <= 50) return 'LOW';
    return 'IN_STOCK';
  };

  const stockStatusLabel = {
    IN_STOCK: 'Còn hàng',
    LOW: 'Sắp hết',
    OUT: 'Hết hàng',
  };

  useEffect(() => {
    fetchProducts();
    fetchCategories();
  }, []);

  const fetchProducts = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (selectedCategory) params.append('categoryId', selectedCategory);
      if (selectedStatus) params.append('status', selectedStatus);
      if (searchTerm.trim()) params.append('search', searchTerm.trim());

      const query = params.toString();
      const res = await api.get(`/inventory/products${query ? `?${query}` : ''}`);
      setProducts(res.data?.data || []);
      setError(null);
    } catch (err) {
      console.error('Lỗi khi tải sản phẩm:', err);
      setError('Không thể tải danh sách sản phẩm');
    } finally {
      setLoading(false);
    }
  };

  const fetchCategories = async () => {
    try {
      const res = await api.get('/inventory/categories');
      setCategories(res.data?.data || []);
    } catch (err) {
      console.error('Lỗi khi tải danh mục:', err);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, [selectedCategory, selectedStatus]);

  const handleSearch = (e) => {
    e.preventDefault();
    fetchProducts();
  };

  const handleOpenModal = (product = null) => {
    if (product) {
      setEditingId(product.product_id);
      setFormData({
        product_code: product.product_code || '',
        product_name: product.product_name || '',
        category_id: String(product.category_id || ''),
        unit: product.unit || '',
        supplier: product.supplier || '',
        description: product.description || '',
        status: product.status || 'ACTIVE',
      });
    } else {
      setEditingId(null);
      setFormData(initialForm);
    }
    setShowModal(true);
  };

  const handleCloseModal = () => {
    setShowModal(false);
    setEditingId(null);
    setFormData(initialForm);
  };

  const resetForm = () => {
    handleCloseModal();
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      setLoading(true);
      setError(null);
      setSuccess(null);

      const payload = {
        product_code: formData.product_code.trim(),
        product_name: formData.product_name.trim(),
        category_id: Number(formData.category_id),
        unit: formData.unit.trim(),
        supplier: formData.supplier?.trim() || null,
        description: formData.description?.trim() || null,
        status: formData.status,
      };

      if (editingId) {
        await api.put(`/inventory/products/${editingId}`, payload);
        setSuccess('Cập nhật sản phẩm thành công');
      } else {
        await api.post('/inventory/products', payload);
        setSuccess('Thêm sản phẩm thành công');
      }

      resetForm();
      fetchProducts();
    } catch (err) {
      console.error('Lỗi khi lưu sản phẩm:', err);
      setError(err.response?.data?.message || 'Không thể lưu sản phẩm');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (productId) => {
    const ok = window.confirm('Bạn có chắc chắn muốn xóa sản phẩm này?');
    if (!ok) return;

    try {
      setLoading(true);
      await api.delete(`/inventory/products/${productId}`);
      setSuccess('Xóa sản phẩm thành công');
      fetchProducts();
    } catch (err) {
      console.error('Lỗi khi xóa sản phẩm:', err);
      setError(err.response?.data?.message || 'Không thể xóa sản phẩm');
    } finally {
      setLoading(false);
    }
  };

  const inventoryStats = useMemo(() => {
    const totalProducts = products.length;
    const activeProducts = products.filter((item) => String(item.status || '').toUpperCase() === 'ACTIVE').length;
    const lowStockProducts = products.filter((item) => getStockStatus(item.stock_quantity) === 'LOW').length;
    const inactiveProducts = products.filter((item) => String(item.status || '').toUpperCase() !== 'ACTIVE').length;

    const groups = [
      { key: 'feed', label: 'Thức ăn thủy sản', match: /thức ăn|feed|cám|thuc an/i, color: '#3b82f6' },
      { key: 'water', label: 'Thuốc xử lý nước', match: /thuốc|xử lý nước|xu ly nuoc/i, color: '#14b8a6' },
      { key: 'chemical', label: 'Hóa chất', match: /hóa chất|hoa chat|chất/i, color: '#f97316' },
      { key: 'bio', label: 'Chế phẩm vi sinh', match: /vi sinh|men|probiotic/i, color: '#ef4444' },
    ];

    const categoryBreakdown = groups.map((group) => ({
      ...group,
      count: products.filter((item) => group.match.test(String(item.category_name || ''))).length,
    }));

    const matched = new Set(
      products
        .filter((item) => groups.some((group) => group.match.test(String(item.category_name || ''))))
        .map((item) => item.product_id),
    );

    const others = products.filter((item) => !matched.has(item.product_id)).length;
    const breakdown = [...categoryBreakdown, { key: 'other', label: 'Khác', count: others, color: '#facc15' }]
      .filter((item) => item.count > 0);

    const totalForChart = breakdown.reduce((sum, item) => sum + item.count, 0) || 1;
    const donutGradient = breakdown.length
      ? `conic-gradient(${breakdown
          .map((item, index) => {
            const start = breakdown.slice(0, index).reduce((sum, row) => sum + row.count, 0);
            const end = start + item.count;
            const startPercent = (start / totalForChart) * 100;
            const endPercent = (end / totalForChart) * 100;
            return `${item.color} ${startPercent}% ${endPercent}%`;
          })
          .join(', ')})`
      : 'conic-gradient(#e5e7eb 0% 100%)';

    const topCategories = [...breakdown].sort((a, b) => b.count - a.count).slice(0, 5);

    return {
      totalProducts,
      activeProducts,
      lowStockProducts,
      inactiveProducts,
      breakdown,
      topCategories,
      donutGradient,
    };
  }, [products]);

  return (
    <div className="storekeeper-inventory dashboard storekeeper-page">
      {error && <div className="storekeeper-inventory__error">{error}</div>}
      {success && <div className="storekeeper-inventory__success">{success}</div>}

      <section className="storekeeper-inventory__hero">
        <div className="storekeeper-inventory__hero-copy">
          <h1>Quản lý sản phẩm</h1>
          <p>Quản lý thông tin và tình trạng sản phẩm trong kho.</p>
        </div>
        <button
          type="button"
          className="storekeeper-inventory__add-btn"
          onClick={() => handleOpenModal()}
        >
          + Thêm sản phẩm mới
        </button>
      </section>

      <section className="storekeeper-inventory__stats-grid">
        <article className="storekeeper-inventory__stat-card storekeeper-inventory__stat-card--blue">
          <div className="storekeeper-inventory__stat-icon">📦</div>
          <div>
            <p>Tổng sản phẩm</p>
            <h3>{inventoryStats.totalProducts}</h3>
          </div>
        </article>
        <article className="storekeeper-inventory__stat-card storekeeper-inventory__stat-card--green">
          <div className="storekeeper-inventory__stat-icon">✅</div>
          <div>
            <p>Sản phẩm còn hàng</p>
            <h3>{inventoryStats.activeProducts}</h3>
          </div>
        </article>
        <article className="storekeeper-inventory__stat-card storekeeper-inventory__stat-card--amber">
          <div className="storekeeper-inventory__stat-icon">⚠️</div>
          <div>
            <p>Sản phẩm sắp hết</p>
            <h3>{inventoryStats.lowStockProducts}</h3>
          </div>
        </article>
        <article className="storekeeper-inventory__stat-card storekeeper-inventory__stat-card--slate">
          <div className="storekeeper-inventory__stat-icon">🗑️</div>
          <div>
            <p>Sản phẩm ngừng sử dụng</p>
            <h3>{inventoryStats.inactiveProducts}</h3>
          </div>
        </article>
      </section>

      <div className="storekeeper-inventory__content-grid">
        <section className="storekeeper-inventory__main-column">
          <form className="storekeeper-inventory__filters" onSubmit={handleSearch}>
            <input
              type="text"
              placeholder="Tìm kiếm danh mục..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="storekeeper-inventory__search"
            />

            <select
              value={selectedStatus}
              onChange={(e) => setSelectedStatus(e.target.value)}
              className="storekeeper-inventory__select"
            >
              <option value="">Trạng thái</option>
              <option value="ACTIVE">ACTIVE</option>
              <option value="INACTIVE">INACTIVE</option>
            </select>

            <select
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
              className="storekeeper-inventory__select"
            >
              <option value="">Danh mục</option>
              {categories.map((category) => (
                <option key={category.category_id} value={category.category_id}>
                  {category.category_name}
                </option>
              ))}
            </select>

            <button type="submit" className="storekeeper-inventory__filter-btn">
              Lọc
            </button>
          </form>

          <div className="storekeeper-inventory__table-wrap">
            <div className="storekeeper-inventory__table-head">
              <h2>Bảng quản lý sản phẩm</h2>
            </div>

            <table className="storekeeper-inventory__table">
              <thead>
                <tr>
                  <th>Mã sản phẩm</th>
                  <th>Tên sản phẩm</th>
                  <th>Danh mục</th>
                  <th>Đơn vị tính</th>
                  <th>Số lượng tồn</th>
                  <th>Nhà cung cấp</th>
                  <th>Trạng thái</th>
                  <th>Ngày cập nhật</th>
                  <th>Hành động</th>
                </tr>
              </thead>
              <tbody>
                {loading ? (
                  <tr>
                    <td colSpan="9" className="storekeeper-inventory__empty">Đang tải dữ liệu...</td>
                  </tr>
                ) : products.length === 0 ? (
                  <tr>
                    <td colSpan="9" className="storekeeper-inventory__empty">Không có sản phẩm nào</td>
                  </tr>
                ) : (
                  products.map((product) => {
                    const stockState = getStockStatus(product.stock_quantity);
                    return (
                      <tr key={product.product_id}>
                        <td>{product.product_code}</td>
                        <td>{product.product_name}</td>
                        <td>{product.category_name || '-'}</td>
                        <td>{product.unit}</td>
                        <td>{Number(product.stock_quantity || 0).toLocaleString('vi-VN')}</td>
                        <td>{product.supplier || '-'}</td>
                        <td>
                          <span className={`storekeeper-inventory__status storekeeper-inventory__status--${stockState.toLowerCase()}`}>
                            {stockStatusLabel[stockState]}
                          </span>
                        </td>
                        <td>{product.updated_at ? new Date(product.updated_at).toLocaleDateString('vi-VN') : '-'}</td>
                        <td>
                          <div className="storekeeper-inventory__actions">
                            <button type="button" className="btn btn-secondary" onClick={() => handleOpenModal(product)}>
                              Sửa
                            </button>
                            <button type="button" className="btn btn-danger" onClick={() => handleDelete(product.product_id)}>
                              Xóa
                            </button>
                          </div>
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        </section>

        <aside className="storekeeper-inventory__side-column">
          <section className="storekeeper-inventory__analytics-card">
            <h3>Thống kê sản phẩm</h3>
            <p>Phân bổ theo danh mục</p>
            <div className="storekeeper-inventory__donut-wrap">
              <div className="storekeeper-inventory__donut" style={{ background: inventoryStats.donutGradient }} />
              <div className="storekeeper-inventory__legend">
                {inventoryStats.breakdown.map((item) => (
                  <div key={item.key} className="storekeeper-inventory__legend-item">
                    <span style={{ background: item.color }} />
                    <small>{item.label}</small>
                    <strong>{item.count}</strong>
                  </div>
                ))}
              </div>
            </div>
          </section>

          <section className="storekeeper-inventory__analytics-card">
            <h3>Thống kê sản phẩm</h3>
            <p>Mức sử dụng theo nhóm</p>
            <div className="storekeeper-inventory__bars">
              {inventoryStats.topCategories.map((item) => {
                const max = Math.max(...inventoryStats.topCategories.map((row) => row.count), 1);
                const width = `${Math.max((item.count / max) * 100, item.count > 0 ? 18 : 6)}%`;
                return (
                  <div key={item.key} className="storekeeper-inventory__bar-row">
                    <div className="storekeeper-inventory__bar-meta">
                      <span>{item.label}</span>
                      <strong>{item.count}</strong>
                    </div>
                    <div className="storekeeper-inventory__bar-track">
                      <span className="storekeeper-inventory__bar-fill" style={{ width, background: item.color }} />
                    </div>
                  </div>
                );
              })}
            </div>
          </section>
        </aside>
      </div>

      {showModal && (
        <div className="storekeeper-inventory__modal" onClick={handleCloseModal}>
          <div className="storekeeper-inventory__modal-content" onClick={(e) => e.stopPropagation()}>
            <div className="storekeeper-inventory__modal-header">
              <h3>{editingId ? 'Cập nhật sản phẩm' : 'Thêm sản phẩm mới'}</h3>
              <button className="storekeeper-inventory__close-btn" onClick={handleCloseModal}>
                ×
              </button>
            </div>

            <form onSubmit={handleSubmit}>
              <div className="storekeeper-inventory__form-row">
                <div className="storekeeper-inventory__form-group">
                  <label>Mã sản phẩm</label>
                  <input
                    type="text"
                    placeholder="Mã sản phẩm"
                    value={formData.product_code}
                    onChange={(e) => setFormData((prev) => ({ ...prev, product_code: e.target.value }))}
                    required
                  />
                </div>
                <div className="storekeeper-inventory__form-group">
                  <label>Tên sản phẩm</label>
                  <input
                    type="text"
                    placeholder="Tên sản phẩm"
                    value={formData.product_name}
                    onChange={(e) => setFormData((prev) => ({ ...prev, product_name: e.target.value }))}
                    required
                  />
                </div>
              </div>

              <div className="storekeeper-inventory__form-row">
                <div className="storekeeper-inventory__form-group">
                  <label>Danh mục</label>
                  <select
                    value={formData.category_id}
                    onChange={(e) => setFormData((prev) => ({ ...prev, category_id: e.target.value }))}
                    required
                  >
                    <option value="">Chọn danh mục</option>
                    {categories.map((category) => (
                      <option key={category.category_id} value={category.category_id}>
                        {category.category_name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="storekeeper-inventory__form-group">
                  <label>Đơn vị</label>
                  <input
                    type="text"
                    placeholder="Đơn vị (kg, lít, ...)"
                    value={formData.unit}
                    onChange={(e) => setFormData((prev) => ({ ...prev, unit: e.target.value }))}
                    required
                  />
                </div>
              </div>

              <div className="storekeeper-inventory__form-row">
                <div className="storekeeper-inventory__form-group">
                  <label>Nhà cung cấp</label>
                  <input
                    type="text"
                    placeholder="Nhà cung cấp"
                    value={formData.supplier}
                    onChange={(e) => setFormData((prev) => ({ ...prev, supplier: e.target.value }))}
                  />
                </div>
                <div className="storekeeper-inventory__form-group">
                  <label>Trạng thái</label>
                  <select
                    value={formData.status}
                    onChange={(e) => setFormData((prev) => ({ ...prev, status: e.target.value }))}
                  >
                    <option value="ACTIVE">ACTIVE</option>
                    <option value="INACTIVE">INACTIVE</option>
                  </select>
                </div>
              </div>

              <div className="storekeeper-inventory__form-group">
                <label>Mô tả</label>
                <textarea
                  placeholder="Mô tả sản phẩm"
                  value={formData.description}
                  onChange={(e) => setFormData((prev) => ({ ...prev, description: e.target.value }))}
                  rows={3}
                />
              </div>

              <div className="storekeeper-inventory__modal-actions">
                <button type="button" className="storekeeper-inventory__button-secondary" onClick={handleCloseModal} disabled={loading}>
                  Hủy
                </button>
                <button type="submit" className="storekeeper-inventory__button-primary" disabled={loading}>
                  {editingId ? 'Lưu thay đổi' : 'Tạo mới'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

    </div>
  );
};

export default StorekeeperInventory;
